# Utilities module that uses shapes

from shapes import Shape, Rectangle, Circle

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def describe_all(shapes: list[Shape]) -> list[str]:
    result: list[str] = []
    for s in shapes:
        result.append(s.describe())
    return result

class ShapeStats:
    @static
    def count_rectangles(shapes: list[Shape]) -> int:
        count: int = 0
        for s in shapes:
            # Type narrowing would need isinstance check
            if isinstance(s, Rectangle):
                count += 1
        return count

    @static
    def count_circles(shapes: list[Shape]) -> int:
        count: int = 0
        for s in shapes:
            if isinstance(s, Circle):
                count += 1
        return count
